/**
 * 邮件订阅区组件
 * @author <smallletters@sina.com>
 * @date 2026-03-27
 * @description 邮件订阅表单，用于收集用户邮箱
 */

"use client";

import { useState } from "react";
import { motion } from "framer-motion";
import { Mail, Send, CheckCircle } from "lucide-react";

export default function Newsletter() {
  const [email, setEmail] = useState("");
  const [isSubmitted, setIsSubmitted] = useState(false);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (email) {
      setIsSubmitted(true);
      setTimeout(() => {
        setIsSubmitted(false);
        setEmail("");
      }, 3000);
    }
  };

  return (
    <section className="py-16 bg-[#1a1a1a]">
      <div className="max-w-4xl mx-auto px-4 sm:px-6 lg:px-8 text-center">
        <motion.div
          initial={{ opacity: 0, y: 20 }}
          whileInView={{ opacity: 1, y: 0 }}
          viewport={{ once: true }}
        >
          {/* 图标 */}
          <div className="inline-flex items-center justify-center w-16 h-16 bg-[#e53935] rounded-full mb-6">
            <Mail size={28} className="text-white" />
          </div>

          {/* 标题 */}
          <h2 className="text-2xl md:text-3xl font-bold text-white mb-4">
            Subscribe to our newsletter
          </h2>

          {/* 描述 */}
          <p className="text-gray-400 mb-8 max-w-xl mx-auto">
            Get special offers, daily deals, discounts and find out what&apos;s new at Everzon. 
            Sign up for the Everzon newsletter.
          </p>

          {/* 表单 */}
          <form onSubmit={handleSubmit} className="flex flex-col sm:flex-row gap-4 max-w-lg mx-auto">
            <div className="flex-1 relative">
              <input
                type="email"
                value={email}
                onChange={(e) => setEmail(e.target.value)}
                placeholder="Enter your email address"
                className="w-full px-4 py-3 pl-12 bg-white/10 border border-white/20 rounded-lg text-white placeholder-gray-400 focus:outline-none focus:border-[#e53935] transition-colors"
                required
              />
              <Mail
                size={18}
                className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-400"
              />
            </div>
            <button
              type="submit"
              disabled={isSubmitted}
              className="px-8 py-3 bg-[#e53935] hover:bg-[#c62828] text-white font-medium rounded-lg transition-colors flex items-center justify-center gap-2 disabled:opacity-70"
            >
              {isSubmitted ? (
                <>
                  <CheckCircle size={18} />
                  Subscribed!
                </>
              ) : (
                <>
                  <Send size={18} />
                  Subscribe
                </>
              )}
            </button>
          </form>

          {/* 隐私提示 */}
          <p className="text-gray-500 text-xs mt-4">
            By subscribing, you agree to our Privacy Policy and consent to receive updates.
          </p>
        </motion.div>
      </div>
    </section>
  );
}
