"use client";

import { useState } from "react";
import { X } from "lucide-react";

export default function TopBanner() {
  const [isVisible, setIsVisible] = useState(true);

  if (!isVisible) return null;

  return (
    <div className="w-full bg-[#1a1a1a] text-white">
      {/* 促销信息 */}
      <div className="bg-[#e53935] py-2 text-center text-sm font-medium">
        <span className="uppercase tracking-wide">
          Spring Sale 5% OFF (sitewide)
        </span>
      </div>
      
      {/* 警告信息 */}
      <div className="relative py-2 px-4 text-center text-xs text-gray-300">
        <p className="max-w-6xl mx-auto">
          WARNING: We only sell vape devices — no nicotine or other substances are included. 
          Devices must not be used to consume illegal materials.
        </p>
        <button
          onClick={() => setIsVisible(false)}
          className="absolute right-4 top-1/2 -translate-y-1/2 text-gray-400 hover:text-white transition-colors"
          aria-label="Close banner"
        >
          <X size={16} />
        </button>
      </div>
    </div>
  );
}
